&lt;td&gt;165 / 12400&lt;/td&gt;
&lt;td&gt;YoungForest&lt;/td&gt;
&lt;td&gt;18&lt;/td&gt;
&lt;td&gt;1:07:14&lt;/td&gt;
&lt;td&gt;0:03:22 🐞1&lt;/td&gt;
&lt;td&gt;0:16:01 🐞1&lt;/td&gt;
